const UpdateAgent = `-- name: UpdateAgent :one
UPDATE agents
SET title = ?,
    description = ?,
    tags = ?,
    avatar = ?,
    background_color = ?,
    plugins = ?,
    chat_config = ?,
    few_shots = ?,
    model = ?,
    params = ?,
    provider = ?,
    system_role = ?,
    tts = ?,
    opening_message = ?,
    opening_questions = ?,
    updated_at = ?
WHERE id = ?
RETURNING id, title, description, tags, avatar, background_color, plugins, chat_config, few_shots, model, params, provider, system_role, tts, "virtual", opening_message, opening_questions, created_at, updated_at
`

type UpdateAgentParams struct {
	Title            sql.NullString `json:"title"`
	Description      sql.NullString `json:"description"`
	Tags             sql.NullString `json:"tags"`
	Avatar           sql.NullString `json:"avatar"`
	BackgroundColor  sql.NullString `json:"backgroundColor"`
	Plugins          sql.NullString `json:"plugins"`
	ChatConfig       sql.NullString `json:"chatConfig"`
	FewShots         sql.NullString `json:"fewShots"`
	Model            sql.NullString `json:"model"`
	Params           sql.NullString `json:"params"`
	Provider         sql.NullString `json:"provider"`
	SystemRole       sql.NullString `json:"systemRole"`
	Tts              sql.NullString `json:"tts"`
	OpeningMessage   sql.NullString `json:"openingMessage"`
	OpeningQuestions sql.NullString `json:"openingQuestions"`
	UpdatedAt        int64          `json:"updatedAt"`
	ID               string         `json:"id"`
}

func (q *Queries) UpdateAgent(ctx context.Context, arg UpdateAgentParams) (Agent, error) {
	row := q.db.QueryRowContext(ctx, UpdateAgent,
		arg.Title,
		arg.Description,
		arg.Tags,
		arg.Avatar,
		arg.BackgroundColor,
		arg.Plugins,
		arg.ChatConfig,
		arg.FewShots,
		arg.Model,
		arg.Params,
		arg.Provider,
		arg.SystemRole,
		arg.Tts,
		arg.OpeningMessage,
		arg.OpeningQuestions,
		arg.UpdatedAt,
		arg.ID,
	)
	var i Agent
	err := row.Scan(
		&i.ID,
		&i.Title,
		&i.Description,
		&i.Tags,
		&i.Avatar,
		&i.BackgroundColor,
		&i.Plugins,
		&i.ChatConfig,
		&i.FewShots,
		&i.Model,
		&i.Params,
		&i.Provider,
		&i.SystemRole,
		&i.Tts,
		&i.Virtual,
		&i.OpeningMessage,
		&i.OpeningQuestions,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return i, err
}
